if n > m:
    return -1
count = m - n + 1
total = (n + m) * count // 2
quotient = total // count
remainder = total % count
if remainder * 2 < count:
    rounded = quotient
elif remainder * 2 > count:
    rounded = quotient + 1
else:
    if quotient % 2 == 0:
        rounded = quotient
    else:
        rounded = quotient + 1
return bin(rounded)
